import { useEffect, useState } from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  BarElement,
  CategoryScale,
  LinearScale
} from "chart.js";

ChartJS.register(BarElement, CategoryScale, LinearScale);

export default function Dashboard() {
  const [data, setData] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/dashboard")
      .then(res => res.json())
      .then(setData);
  }, []);

  const chartData = {
    labels: data.map(d => `Center ${d.center_id}`),
    datasets: [
      {
        label: "Doses",
        data: data.map(d => d.count)
      }
    ]
  };

  return (
    <div className="container">
      <div className="card" style={{ width: "600px" }}>
        <h2>Dashboard</h2>

        {/* TABLE */}
        <table>
          <thead>
            <tr>
              <th>Center</th>
              <th>Date</th>
              <th>Doses</th>
            </tr>
          </thead>

          <tbody>
            {data.map((d, i) => (
              <tr key={i}>
                <td>{d.center_id}</td>
                <td>{d.date || "N/A"}</td>
                <td>{d.count || 0}</td>
              </tr>
            ))}
          </tbody>
        </table>

        {/* CHART */}
        <h3 style={{ marginTop: "20px" }}>Dose Distribution</h3>
        <Bar data={chartData} />
      </div>
    </div>
  );
}
